import React from 'react';

const SeleccionarTipoOferta = ({ onSeleccionar }) => {
  return (
    <>
      <style>{`
        @import url('https://fonts.googleapis.com/css2?family=Sora:wght@300;400;500;600&display=swap');

        .sto-page {
          font-family: 'Sora', sans-serif;
          background: #f4f7f5;
          min-height: 100vh;
          display: flex;
          align-items: center;
          justify-content: center;
          padding: 40px 24px;
          box-sizing: border-box;
        }

        .sto-card {
          background: #fff;
          border: 1px solid #e0ebe4;
          border-radius: 20px;
          width: 100%;
          max-width: 600px;
          padding: 52px 44px;
          position: relative;
          box-sizing: border-box;
          text-align: center;
        }

        .sto-card::before {
          content: '';
          position: absolute;
          top: -1px; left: 50%; transform: translateX(-50%);
          width: 160px; height: 3px;
          background: #00643C;
          border-radius: 0 0 4px 4px;
        }

        .sto-logo {
          display: inline-flex;
          background: #00643C;
          border-radius: 10px;
          padding: 8px 14px;
          font-size: 15px;
          font-weight: 600;
          color: white;
          letter-spacing: 2px;
          margin-bottom: 28px;
        }

        .sto-eyebrow {
          font-size: 11px;
          letter-spacing: 2px;
          text-transform: uppercase;
          color: #00643C;
          font-weight: 500;
          margin-bottom: 6px;
        }

        .sto-title {
          font-size: 22px;
          font-weight: 600;
          color: #111;
          margin: 0 0 8px 0;
          line-height: 1.3;
        }

        .sto-sub {
          font-size: 13px;
          color: #7a8f82;
          margin: 0 0 40px 0;
          line-height: 1.6;
        }

        .sto-options {
          display: flex;
          gap: 16px;
          justify-content: center;
        }

        .sto-option {
          flex: 1;
          padding: 28px 20px;
          border-radius: 14px;
          border: 1.5px solid #e0ebe4;
          background: #f8faf9;
          cursor: pointer;
          text-align: left;
          transition: all 0.2s;
          position: relative;
          overflow: hidden;
          font-family: 'Sora', sans-serif;
        }

        .sto-option::after {
          content: '';
          position: absolute;
          bottom: 0; left: 0; right: 0;
          height: 3px;
          border-radius: 0 0 14px 14px;
          opacity: 0;
          transition: opacity 0.2s;
        }

        .sto-option:hover {
          border-color: #00643C;
          background: #fff;
          transform: translateY(-2px);
          box-shadow: 0 8px 24px rgba(0,100,60,0.1);
        }

        .sto-option:hover::after { opacity: 1; }

        .sto-option-regular::after { background: #00643C; }
        .sto-option-campesena::after { background: #e67e22; }

        .sto-option:active { transform: scale(0.99); }

        .sto-icon {
          width: 44px; height: 44px;
          border-radius: 12px;
          display: flex; align-items: center; justify-content: center;
          font-size: 20px;
          margin-bottom: 16px;
        }

        .sto-icon-regular { background: #e8f5ef; }
        .sto-icon-campesena { background: #fef3e8; }

        .sto-option-title {
          font-size: 15px;
          font-weight: 600;
          color: #111;
          margin-bottom: 6px;
          letter-spacing: 0.3px;
        }

        .sto-option-desc {
          font-size: 12px;
          color: #7a8f82;
          line-height: 1.55;
        }

        .sto-option-tag {
          display: inline-block;
          font-size: 10px;
          font-weight: 600;
          letter-spacing: 1px;
          text-transform: uppercase;
          padding: 3px 8px;
          border-radius: 20px;
          margin-bottom: 12px;
        }

        .sto-tag-regular {
          background: #e8f5ef;
          color: #00643C;
        }

        .sto-tag-campesena {
          background: #fef3e8;
          color: #c0621a;
        }

        .sto-arrow {
          position: absolute;
          top: 50%; right: 18px;
          transform: translateY(-50%);
          font-size: 16px;
          color: #b8ccc0;
          transition: color 0.2s, right 0.2s;
        }

        .sto-option:hover .sto-arrow {
          color: #00643C;
          right: 14px;
        }

        .sto-footer {
          margin-top: 36px;
          font-size: 11px;
          color: #b8ccc0;
          letter-spacing: 0.3px;
        }

        @media (max-width: 480px) {
          .sto-card { padding: 40px 24px; }
          .sto-options { flex-direction: column; }
        }
      `}</style>

      <div className="sto-page">
        <div className="sto-card">

          <div className="sto-logo">SENA</div>

          <p className="sto-eyebrow">Nueva oferta</p>
          <h2 className="sto-title">¿Qué tipo de oferta deseas crear?</h2>
          <p className="sto-sub">Selecciona el tipo de oferta según el programa que vas a registrar en la plataforma.</p>

          <div className="sto-options">

            <button className="sto-option sto-option-regular" onClick={() => onSeleccionar('regular')}>
              <div className="sto-option-tag sto-tag-regular">Estándar</div>
              <div className="sto-icon sto-icon-regular">🌿</div>
              <div className="sto-option-title">Regular</div>
              <div className="sto-option-desc">Formación estándar sin instructores adicionales. Duración flexible según programa.</div>
              <span className="sto-arrow">→</span>
            </button>

            <button className="sto-option sto-option-campesena" onClick={() => onSeleccionar('campesena')}>
              <div className="sto-option-tag sto-tag-campesena">Especial</div>
              <div className="sto-icon sto-icon-campesena">🌾</div>
              <div className="sto-option-title">Campesena</div>
              <div className="sto-option-desc">Incluye 2 instructores adicionales. Duración fija de 5 meses para comunidades rurales.</div>
              <span className="sto-arrow">→</span>
            </button>

          </div>

          <div className="sto-footer">© 2025 SENA · Servicio Nacional de Aprendizaje</div>
        </div>
      </div>
    </>
  );
};

export default SeleccionarTipoOferta;
